class TOTPManager:
    def __init__(self, encryption_key=None):
        if encryption_key:
            self.cipher = Fernet(encryption_key)
        else:
            self.cipher = None
    
    def generate_secret(self):
        """Generate a secure TOTP secret"""
        return pyotp.random_base32()
    
    def create_qr_code(self, secret, user_email, issuer_name):
        """Create QR code for authenticator app setup"""
        totp_uri = pyotp.totp.TOTP(secret).provisioning_uri(
            user_email, issuer_name=issuer_name
        )
        
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(totp_uri)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        buffer = BytesIO()
        img.save(buffer, format="PNG")
        buffer.seek(0)
        
        return buffer.getvalue()
    
    def validate_totp(self, secret, token, valid_window=1):
        """Validate TOTP token with window for clock drift"""
        totp = pyotp.TOTP(secret)
        return totp.verify(token, valid_window=valid_window)
    
    def generate_totp(self, secret):
        """Generate current TOTP code"""
        totp = pyotp.TOTP(secret)
        return totp.now()
    
    def encrypt_secret(self, secret):
        """Encrypt secret if encryption key is provided"""
        if self.cipher:
            return self.cipher.encrypt(secret.encode()).decode()
        return secret
    
    def decrypt_secret(self, encrypted_secret):
        """Decrypt secret if encryption key is provided"""
        if self.cipher:
            return self.cipher.decrypt(encrypted_secret.encode()).decode()
        return encrypted_secret

