class SecureTOTP:
    def __init__(self):
        self.totp_manager = TOTPManager()
        self.user_secrets = {}
    
    def register_user(self, user_id, email, issuer_name="SecureApp"):
        """Register a new user with TOTP"""
        try:
            secret = self.totp_manager.generate_secret()
            encrypted_secret = self.totp_manager.encrypt_secret(secret)
            self.user_secrets[user_id] = {
                'secret': encrypted_secret,
                'email': email,
                'issuer': issuer_name
            }
            return secret
        except Exception as e:
            raise Exception(f"Registration failed: {str(e)}")
    
    def get_qr_code(self, user_id):
        """Get QR code for user setup"""
        try:
            user_data = self.user_secrets.get(user_id)
            if not user_data:
                raise ValueError("User not found")
            
            secret = self.totp_manager.decrypt_secret(user_data['secret'])
            return self.totp_manager.create_qr_code(
                secret, user_data['email'], user_data['issuer']
            )
        except Exception as e:
            raise Exception(f"QR code generation failed: {str(e)}")
    
    def verify_token(self, user_id, token):
        """Verify TOTP token for user"""
        try:
            user_data = self.user_secrets.get(user_id)
            if not user_data:
                return False
            
            secret = self.totp_manager.decrypt_secret(user_data['secret'])
            return self.totp_manager.validate_totp(secret, token)
        except Exception:
            return False
    
    def generate_current_code(self, user_id):
        """Generate current TOTP code for user"""
        try:
            user_data = self.user_secrets.get(user_id)
            if not user_data:
                raise ValueError("User not found")
            
            secret = self.totp_manager.decrypt_secret(user_data['secret'])
            return self.totp_manager.generate_totp(secret)
        except Exception as e:
            raise Exception(f"Code generation failed: {str(e)}")

